import{_ as a,o as t,c as o,ag as i}from"./chunks/framework.NIzFHKo_.js";const p=JSON.parse('{"title":"Agent Governance Layer","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/10_governance/20_rules/_index.md","filePath":"10_core/10_governance/20_rules/_index.md"}'),r={name:"10_core/10_governance/20_rules/_index.md"};function n(l,e,s,c,d,h){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="agent-governance-layer" tabindex="-1">Agent Governance Layer <a class="header-anchor" href="#agent-governance-layer" aria-label="Permalink to &quot;Agent Governance Layer&quot;">​</a></h1><p>Version: 1.1 Status: Active Scope: All AI-assisted systems, IDE agents, automation workers, and code generators</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>This document defines the mandatory behavior constraints for agents operating inside the QiAccess Start blueprint.</p><p>Agents do not get to invent the architecture. Agents must enforce the active doctrine.</p><h2 id="core-principle" tabindex="-1">Core Principle <a class="header-anchor" href="#core-principle" aria-label="Permalink to &quot;Core Principle&quot;">​</a></h2><blockquote><p>Agents do not create architecture. Agents enforce architecture.</p></blockquote><h2 id="agent-behavioral-modes" tabindex="-1">Agent Behavioral Modes <a class="header-anchor" href="#agent-behavioral-modes" aria-label="Permalink to &quot;Agent Behavioral Modes&quot;">​</a></h2><h3 id="_1-doctrine-alignment-mode" tabindex="-1">1. Doctrine Alignment Mode <a class="header-anchor" href="#_1-doctrine-alignment-mode" aria-label="Permalink to &quot;1. Doctrine Alignment Mode&quot;">​</a></h3><ul><li>load and interpret active blueprint pages first</li><li>validate constraints before action</li></ul><h3 id="_2-implementation-mode" tabindex="-1">2. Implementation Mode <a class="header-anchor" href="#_2-implementation-mode" aria-label="Permalink to &quot;2. Implementation Mode&quot;">​</a></h3><ul><li>execute within approved structure</li><li>avoid structural invention</li></ul><h3 id="_3-audit-mode" tabindex="-1">3. Audit Mode <a class="header-anchor" href="#_3-audit-mode" aria-label="Permalink to &quot;3. Audit Mode&quot;">​</a></h3><ul><li>detect violations, drift, and contradictions</li></ul><h3 id="_4-escalation-mode" tabindex="-1">4. Escalation Mode <a class="header-anchor" href="#_4-escalation-mode" aria-label="Permalink to &quot;4. Escalation Mode&quot;">​</a></h3><ul><li>stop when ownership, truth, or root placement is unclear</li></ul><h2 id="mandatory-pre-action-validation" tabindex="-1">Mandatory Pre-Action Validation <a class="header-anchor" href="#mandatory-pre-action-validation" aria-label="Permalink to &quot;Mandatory Pre-Action Validation&quot;">​</a></h2><p>Before any action, agents must determine:</p><ul><li>Which root or system subroute owns this?</li><li>Which layer or governance control applies?</li><li>What schema, file, or service is the owner?</li><li>Is this canonical or derived?</li><li>Does the active runtime require owner-scoped access or protected system scope?</li><li>Is the referenced doctrine active, future-state, or quarantined legacy?</li><li>Does this intake path require capture or registration before downstream use?</li></ul><p>If any answer is unclear:</p><p><code>HARD STOP - escalate</code></p><h2 id="non-negotiable-system-laws" tabindex="-1">Non-Negotiable System Laws <a class="header-anchor" href="#non-negotiable-system-laws" aria-label="Permalink to &quot;Non-Negotiable System Laws&quot;">​</a></h2><h3 id="_1-seven-root-integrity" tabindex="-1">1. Seven-Root Integrity <a class="header-anchor" href="#_1-seven-root-integrity" aria-label="Permalink to &quot;1. Seven-Root Integrity&quot;">​</a></h3><p>No new top-level root may be introduced without blueprint approval.</p><h3 id="_2-single-domain-ownership" tabindex="-1">2. Single Domain Ownership <a class="header-anchor" href="#_2-single-domain-ownership" aria-label="Permalink to &quot;2. Single Domain Ownership&quot;">​</a></h3><p>Each canonical object has one clear home.</p><h3 id="_3-public-schema-restriction" tabindex="-1">3. Public Schema Restriction <a class="header-anchor" href="#_3-public-schema-restriction" aria-label="Permalink to &quot;3. Public Schema Restriction&quot;">​</a></h3><p>Do not move domain logic or sensitive control into public, weakly governed surfaces.</p><h3 id="_4-active-runtime-isolation" tabindex="-1">4. Active Runtime Isolation <a class="header-anchor" href="#_4-active-runtime-isolation" aria-label="Permalink to &quot;4. Active Runtime Isolation&quot;">​</a></h3><p>Enforce the current runtime model that actually exists. Do not inject tenant assumptions into active work unless a page explicitly marks them as current.</p><h3 id="_5-capture-or-registration-before-derivation" tabindex="-1">5. Capture or Registration Before Derivation <a class="header-anchor" href="#_5-capture-or-registration-before-derivation" aria-label="Permalink to &quot;5. Capture or Registration Before Derivation&quot;">​</a></h3><p>Externally ingested signals, files, messages, and observations must enter through an approved intake path before derived processing.</p><h3 id="_6-canonical-versus-derived-separation" tabindex="-1">6. Canonical Versus Derived Separation <a class="header-anchor" href="#_6-canonical-versus-derived-separation" aria-label="Permalink to &quot;6. Canonical Versus Derived Separation&quot;">​</a></h3><p>AI, vectors, exports, and graph layers cannot define truth.</p><h3 id="_7-no-parallel-systems" tabindex="-1">7. No Parallel Systems <a class="header-anchor" href="#_7-no-parallel-systems" aria-label="Permalink to &quot;7. No Parallel Systems&quot;">​</a></h3><p>Do not create duplicate pipelines, schemas, roots, or shadow logic.</p><h3 id="_8-schema-authority" tabindex="-1">8. Schema Authority <a class="header-anchor" href="#_8-schema-authority" aria-label="Permalink to &quot;8. Schema Authority&quot;">​</a></h3><p>Migrations and approved runtime contracts define reality, not speculative code structure.</p><h3 id="_9-migration-first-enforcement" tabindex="-1">9. Migration-First Enforcement <a class="header-anchor" href="#_9-migration-first-enforcement" aria-label="Permalink to &quot;9. Migration-First Enforcement&quot;">​</a></h3><p>Do not present ORM models or inline DDL as the source of truth for canonical schema changes.</p><h3 id="_10-no-implicit-doctrine-promotion" tabindex="-1">10. No Implicit Doctrine Promotion <a class="header-anchor" href="#_10-no-implicit-doctrine-promotion" aria-label="Permalink to &quot;10. No Implicit Doctrine Promotion&quot;">​</a></h3><p>Do not promote legacy or informal material into active doctrine without explicit blueprint alignment.</p><h2 id="out-of-bounds-protocol" tabindex="-1">Out-of-Bounds Protocol <a class="header-anchor" href="#out-of-bounds-protocol" aria-label="Permalink to &quot;Out-of-Bounds Protocol&quot;">​</a></h2><p>If a violation is detected, agents must return:</p><ol><li>Deviation</li><li>Ripple impact</li><li>Pros and cons</li><li>Approval request</li></ol><p>Agents must not continue with partial structural work once they know the request is out of bounds.</p><h2 id="adr-trigger-rule" tabindex="-1">ADR Trigger Rule <a class="header-anchor" href="#adr-trigger-rule" aria-label="Permalink to &quot;ADR Trigger Rule&quot;">​</a></h2><p>Agents must recommend ADR creation when:</p><ul><li>a rule is intentionally bypassed</li><li>a new structural pattern emerges</li><li>a repeated exception becomes normal behavior</li><li>a root, ownership, or boundary changes</li></ul><h2 id="enforcement-priority" tabindex="-1">Enforcement Priority <a class="header-anchor" href="#enforcement-priority" aria-label="Permalink to &quot;Enforcement Priority&quot;">​</a></h2><p>Resolve conflicts in this order:</p><ol><li>Active master blueprint doctrine</li><li>Approved ADRs</li><li>Migrations and implementation truth</li><li>Quarantined legacy material</li></ol><p>User requests that conflict with higher-priority doctrine must be treated as escalation triggers.</p>',53)])])}const m=a(r,[["render",n]]);export{p as __pageData,m as default};
